import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class PathTraversalExample {

    private static final String BASE_DIRECTORY = "/var/www/files/";

    public static void main(String[] args) {
        String userInput = "/path/to/sensitive/file.txt";

        // Sanitize user input to prevent directory traversal
        if (!userInput.contains("..")) {
            try {
                File file = new File(BASE_DIRECTORY + userInput);
                if (file.getCanonicalPath().startsWith(BASE_DIRECTORY) && file.exists()) {
                    byte[] fileData = Files.readAllBytes(file.toPath());
                    System.out.println(new String(fileData));
                } else {
                    System.out.println("File not found");
                }
            } catch (IOException e) {
                System.out.println("An error occurred: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path");
        }
    }
}

